1	import React, { useState, useEffect, useCallback } from 'react';
2	import client from '../api/client';
3	import LoadingSpinner from '../components/LoadingSpinner';
4	import { useAuthStore } from '../store/authStore';
5	
6	const DISPUTE_STATUS_COLORS = {
7	  created: 'bg-gray-100 text-gray-700',
8	  evidence_uploaded: 'bg-yellow-100 text-yellow-700',
9	  under_review: 'bg-blue-100 text-blue-700',
10	  arbitration: 'bg-purple-100 text-purple-700',
11	  resolved_hidden: 'bg-red-100 text-red-700',
12	  resolved_disclaimer: 'bg-orange-100 text-orange-700',
13	  resolved_restored: 'bg-green-100 text-green-700',
14	  rejected: 'bg-gray-200 text-gray-600',
15	};
16	
17	const REVIEW_STATUS_ICONS = {
18	  visible: { label: 'Visible', color: 'text-green-600' },
19	  hidden: { label: 'Hidden', color: 'text-red-600' },
20	  disclaimer: { label: 'Disclaimer', color: 'text-orange-600' },
21	};
22	
23	export default function DisputeQueue() {
24	  const { hasAnyRole } = useAuthStore();
25	  // Only procurement_specialist and system_admin can access /procurement/reviews
26	  const canViewReviews = hasAnyRole('procurement_specialist', 'system_admin');
27	  // Only procurement_specialist and system_admin can create disputes
28	  const canCreateDispute = hasAnyRole('procurement_specialist', 'system_admin');
29	  // Only content_moderator and system_admin can arbitrate disputes
30	  const canArbitrate = hasAnyRole('content_moderator', 'system_admin');
31	
32	  const [disputes, setDisputes] = useState([]);
33	  const [reviews, setReviews] = useState([]);
34	  const [selectedDispute, setSelectedDispute] = useState(null);
35	  const [loading, setLoading] = useState(true);
36	  const [error, setError] = useState(null);
37	  const [actionMsg, setActionMsg] = useState('');
38	
39	  // Transition form state
40	  const [transForm, setTransForm] = useState({
41	    evidence_urls: '',
42	    merchant_response: '',
43	    arbitration_notes: '',
44	    arbitration_outcome: 'restore',
45	  });
46	
47	  const fetchData = useCallback(async () => {
48	    setLoading(true);
49	    setError(null);
50	    try {
51	      const fetches = [client.get('/procurement/disputes')];
52	      // Only fetch reviews if the user's role permits it
53	      if (canViewReviews) {
54	        fetches.push(client.get('/procurement/reviews'));
55	      }
56	      const results = await Promise.all(fetches);
57	      setDisputes(results[0].data || []);
58	      setReviews(canViewReviews ? (results[1].data || []) : []);
59	    } catch (err) {
60	      setError(err.response?.data?.message || 'Failed to load dispute data');
61	    } finally {
62	      setLoading(false);
63	    }
64	  }, [canViewReviews]);
65	
66	  useEffect(() => { fetchData(); }, [fetchData]);
67	
68	  const handleTransition = async (disputeId, action) => {
69	    setError(null);
70	    try {
71	      const payload = { dispute_id: disputeId, action };
72	
73	      if (action === 'upload_evidence') {
74	        const urls = transForm.evidence_urls.split('\n').map(s => s.trim()).filter(Boolean);
75	        if (urls.length === 0) {
76	          setError('At least one evidence URL is required');
77	          return;
78	        }
79	        payload.evidence_urls = urls;
80	      }
81	      if (action === 'respond') {
82	        if (!transForm.merchant_response.trim()) {
83	          setError('Merchant response text is required');
84	          return;
85	        }
86	        payload.merchant_response = transForm.merchant_response;
87	      }
88	      if (action === 'arbitrate') {
89	        payload.arbitration_notes = transForm.arbitration_notes;
90	        payload.arbitration_outcome = transForm.arbitration_outcome;
91	      }
92	      if (action === 'reject') {
93	        payload.arbitration_notes = transForm.arbitration_notes;
94	      }
95	
96	      await client.post('/procurement/disputes/transition', payload);
97	      setActionMsg(`Dispute ${action.replace(/_/g, ' ')} successful`);
98	      setTransForm({ evidence_urls: '', merchant_response: '', arbitration_notes: '', arbitration_outcome: 'restore' });
99	      setSelectedDispute(null);
100	      fetchData();
101	    } catch (err) {
102	      setError(err.response?.data?.message || `Action ${action} failed`);
103	    }
104	  };
105	
106	  if (loading) return <LoadingSpinner text="Loading dispute queue..." />;
107	
108	  const activeDisputes = disputes.filter(d => !d.status.startsWith('resolved_') && d.status !== 'rejected');
109	  const resolvedDisputes = disputes.filter(d => d.status.startsWith('resolved_') || d.status === 'rejected');
110	
111	  return (
112	    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
113	      <h1 className="text-2xl font-bold text-gray-900 mb-6">Review Disputes</h1>
114	
115	      {error && (
116	        <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-md text-sm text-red-700">
117	          {error} <button onClick={() => setError(null)} className="ml-2 font-medium">Dismiss</button>
118	        </div>
119	      )}
120	      {actionMsg && (
121	        <div className="mb-4 p-3 bg-green-50 border border-green-200 rounded-md text-sm text-green-700">
122	          {actionMsg} <button onClick={() => setActionMsg('')} className="ml-2 font-medium">Dismiss</button>
123	        </div>
124	      )}
125	
126	      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
127	        {/* Dispute list */}
128	        <div className="lg:col-span-1">
129	          <h2 className="text-sm font-semibold text-gray-700 mb-3 uppercase tracking-wider">
130	            Active ({activeDisputes.length})
131	          </h2>
132	          <div className="space-y-2 mb-6">
133	            {activeDisputes.map((d) => (
134	              <button
135	                key={d.id}
136	                onClick={() => setSelectedDispute(d)}
137	                className={`w-full text-left p-3 rounded-lg border transition-all ${
138	                  selectedDispute?.id === d.id ? 'border-primary-500 bg-primary-50 shadow-sm' : 'border-gray-200 bg-white hover:border-gray-300'
139	                }`}
140	              >
141	                <div className="flex items-center justify-between mb-1">
142	                  <span className="text-sm font-medium text-gray-800">#{d.id} - {d.vendor_name}</span>
143	                  <span className={`px-1.5 py-0.5 rounded text-[10px] font-medium ${DISPUTE_STATUS_COLORS[d.status]}`}>
144	                    {d.status.replace(/_/g, ' ')}
145	                  </span>
146	                </div>
147	                <p className="text-xs text-gray-500 line-clamp-2">{d.reason}</p>
148	              </button>
149	            ))}
150	            {activeDisputes.length === 0 && (
151	              <p className="text-sm text-gray-400 text-center py-4">No active disputes</p>
152	            )}
153	          </div>
154	
155	          <h2 className="text-sm font-semibold text-gray-700 mb-3 uppercase tracking-wider">
156	            Resolved ({resolvedDisputes.length})
157	          </h2>
158	          <div className="space-y-2">
159	            {resolvedDisputes.map((d) => (
160	              <button
161	                key={d.id}
162	                onClick={() => setSelectedDispute(d)}
163	                className={`w-full text-left p-3 rounded-lg border transition-all ${
164	                  selectedDispute?.id === d.id ? 'border-primary-500 bg-primary-50' : 'border-gray-200 bg-white hover:border-gray-300'
165	                }`}
166	              >
167	                <div className="flex items-center justify-between mb-1">
168	                  <span className="text-sm font-medium text-gray-600">#{d.id} - {d.vendor_name}</span>
169	                  <span className={`px-1.5 py-0.5 rounded text-[10px] font-medium ${DISPUTE_STATUS_COLORS[d.status]}`}>
170	                    {d.status.replace(/_/g, ' ')}
171	                  </span>
172	                </div>
173	              </button>
174	            ))}
175	          </div>
176	        </div>
177	
178	        {/* Dispute detail + actions */}
179	        <div className="lg:col-span-2">
180	          {selectedDispute ? (
181	            <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
182	              <div className="flex items-start justify-between mb-4">
183	                <div>
184	                  <h3 className="text-lg font-semibold text-gray-900">Dispute #{selectedDispute.id}</h3>
185	                  <p className="text-sm text-gray-500">Vendor: {selectedDispute.vendor_name} | Review #{selectedDispute.review_id}</p>
186	                </div>
187	                <span className={`px-2 py-1 rounded text-xs font-medium ${DISPUTE_STATUS_COLORS[selectedDispute.status]}`}>
188	                  {selectedDispute.status.replace(/_/g, ' ')}
189	                </span>
190	              </div>
191	
192	              {/* State machine visualization */}
193	              <div className="mb-6 flex items-center space-x-1 text-xs overflow-x-auto pb-2">
194	                {['created', 'evidence_uploaded', 'under_review', 'arbitration', 'resolved'].map((step, i) => {
195	                  const isCurrent = selectedDispute.status === step ||
196	                    (step === 'resolved' && selectedDispute.status.startsWith('resolved_'));
197	                  const isPast = ['created', 'evidence_uploaded', 'under_review', 'arbitration', 'resolved']
198	                    .indexOf(step) < ['created', 'evidence_uploaded', 'under_review', 'arbitration']
199	                    .indexOf(selectedDispute.status);
200	                  return (
201	                    <React.Fragment key={step}>
202	                      {i > 0 && <span className="text-gray-300">-</span>}
203	                      <span className={`px-2 py-1 rounded whitespace-nowrap ${
204	                        isCurrent ? 'bg-primary-600 text-white' : isPast ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'
205	                      }`}>
206	                        {step.replace(/_/g, ' ')}
207	                      </span>
208	                    </React.Fragment>
209	                  );
210	                })}
211	              </div>
212	
213	              <div className="space-y-4">
214	                <div>
215	                  <h4 className="text-xs font-semibold text-gray-500 uppercase mb-1">Reason</h4>
216	                  <p className="text-sm text-gray-800">{selectedDispute.reason}</p>
217	                </div>
218	
219	                {selectedDispute.evidence_urls && selectedDispute.evidence_urls.length > 0 && (
220	                  <div>
221	                    <h4 className="text-xs font-semibold text-gray-500 uppercase mb-1">Evidence</h4>
222	                    <ul className="list-disc list-inside text-sm text-blue-600">
223	                      {selectedDispute.evidence_urls.map((url, i) => (
224	                        <li key={i}>{url}</li>
225	                      ))}
226	                    </ul>
227	                  </div>
228	                )}
229	
230	                {selectedDispute.merchant_response && (
231	                  <div>
232	                    <h4 className="text-xs font-semibold text-gray-500 uppercase mb-1">Merchant Response</h4>
233	                    <p className="text-sm text-gray-800 bg-yellow-50 p-3 rounded">{selectedDispute.merchant_response}</p>
234	                  </div>
235	                )}
236	
237	                {selectedDispute.arbitration_notes && (
238	                  <div>
239	                    <h4 className="text-xs font-semibold text-gray-500 uppercase mb-1">Arbitration Notes</h4>
240	                    <p className="text-sm text-gray-800">{selectedDispute.arbitration_notes}</p>
241	                  </div>
242	                )}
243	
244	                {selectedDispute.arbitration_outcome && (
245	                  <div>
246	                    <h4 className="text-xs font-semibold text-gray-500 uppercase mb-1">Outcome</h4>
247	                    <span className="text-sm font-medium capitalize">{selectedDispute.arbitration_outcome}</span>
248	                  </div>
249	                )}
250	              </div>
251	
252	              {/* Actions based on current status and user role */}
253	              <div className="mt-6 pt-4 border-t border-gray-200">
254	                {selectedDispute.status === 'created' && canCreateDispute && (
255	                  <div>
256	                    <h4 className="text-sm font-semibold text-gray-700 mb-2">Submit Evidence URLs</h4>
257	                    <p className="text-xs text-gray-500 mb-2">
258	                      Enter one URL per line (max 20). Use intranet URLs or file paths to evidence documents
259	                      accessible within your local network (e.g., <code>http://fileserver/evidence/doc.pdf</code>).
260	                    </p>
261	                    <textarea
262	                      value={transForm.evidence_urls}
263	                      onChange={(e) => setTransForm(f => ({ ...f, evidence_urls: e.target.value }))}
264	                      placeholder="http://fileserver/evidence/contract.pdf&#10;http://fileserver/evidence/invoice_scan.pdf"
265	                      className="w-full border rounded-md px-3 py-2 text-sm mb-2 h-20 font-mono text-xs"
266	                    />
267	                    <button onClick={() => handleTransition(selectedDispute.id, 'upload_evidence')}
268	                      className="px-4 py-2 bg-yellow-500 text-white rounded-md text-sm hover:bg-yellow-600">
269	                      Upload Evidence
270	                    </button>
271	                  </div>
272	                )}
273	
274	                {selectedDispute.status === 'evidence_uploaded' && canCreateDispute && (
275	                  <div className="space-y-3">
276	                    <div>
277	                      <h4 className="text-sm font-semibold text-gray-700 mb-2">Merchant Response</h4>
278	                      <textarea
279	                        value={transForm.merchant_response}
280	                        onChange={(e) => setTransForm(f => ({ ...f, merchant_response: e.target.value }))}
281	                        placeholder="Enter merchant's response..."
282	                        className="w-full border rounded-md px-3 py-2 text-sm mb-2 h-20"
283	                      />
284	                      <button onClick={() => handleTransition(selectedDispute.id, 'respond')}
285	                        className="px-4 py-2 bg-gray-600 text-white rounded-md text-sm hover:bg-gray-700 mr-2">
286	                        Submit Response
287	                      </button>
288	                    </div>
289	                    <button onClick={() => handleTransition(selectedDispute.id, 'start_review')}
290	                      className="px-4 py-2 bg-blue-600 text-white rounded-md text-sm hover:bg-blue-700">
291	                      Start Review
292	                    </button>
293	                  </div>
294	                )}
295	
296	                {selectedDispute.status === 'under_review' && canArbitrate && (
297	                  <div className="space-y-3">
298	                    <textarea
299	                      value={transForm.merchant_response}
300	                      onChange={(e) => setTransForm(f => ({ ...f, merchant_response: e.target.value }))}
301	                      placeholder="Enter merchant's response (optional)..."
302	                      className="w-full border rounded-md px-3 py-2 text-sm h-16"
303	                    />
304	                    <div className="flex space-x-2">
305	                      {transForm.merchant_response && (
306	                        <button onClick={() => handleTransition(selectedDispute.id, 'respond')}
307	                          className="px-3 py-2 bg-gray-500 text-white rounded-md text-sm hover:bg-gray-600">
308	                          Record Response
309	                        </button>
310	                      )}
311	                      <button onClick={() => handleTransition(selectedDispute.id, 'escalate_arbitration')}
312	                        className="px-4 py-2 bg-purple-600 text-white rounded-md text-sm hover:bg-purple-700">
313	                        Escalate to Arbitration
314	                      </button>
315	                    </div>
316	                  </div>
317	                )}
318	
319	                {selectedDispute.status === 'arbitration' && canArbitrate && (
320	                  <div className="space-y-3">
321	                    <h4 className="text-sm font-semibold text-gray-700">Arbitration Decision</h4>
322	                    <textarea
323	                      value={transForm.arbitration_notes}
324	                      onChange={(e) => setTransForm(f => ({ ...f, arbitration_notes: e.target.value }))}
325	                      placeholder="Arbitration notes..."
326	                      className="w-full border rounded-md px-3 py-2 text-sm h-20"
327	                    />
328	                    <div className="flex items-center space-x-3">
329	                      <label className="text-sm text-gray-600">Outcome:</label>
330	                      <select
331	                        value={transForm.arbitration_outcome}
332	                        onChange={(e) => setTransForm(f => ({ ...f, arbitration_outcome: e.target.value }))}
333	                        className="border rounded-md px-3 py-1.5 text-sm"
334	                      >
335	                        <option value="restore">Restore review (visible)</option>
336	                        <option value="disclaimer">Show with disclaimer</option>
337	                        <option value="hide">Hide review</option>
338	                      </select>
339	                    </div>
340	                    <div className="flex space-x-2 pt-2">
341	                      <button onClick={() => handleTransition(selectedDispute.id, 'arbitrate')}
342	                        className="px-4 py-2 bg-green-600 text-white rounded-md text-sm hover:bg-green-700">
343	                        Resolve
344	                      </button>
345	                      <button onClick={() => handleTransition(selectedDispute.id, 'reject')}
346	                        className="px-4 py-2 bg-red-500 text-white rounded-md text-sm hover:bg-red-600">
347	                        Reject Dispute
348	                      </button>
349	                    </div>
350	                  </div>
351	                )}
352	              </div>
353	            </div>
354	          ) : (
355	            <div className="bg-gray-50 rounded-lg p-12 text-center text-gray-400">
356	              <p className="text-lg">Select a dispute to view details</p>
357	              <p className="text-sm mt-1">Click on a dispute from the list on the left</p>
358	            </div>
359	          )}
360	        </div>
361	      </div>
362	
363	      {/* Reviews with statuses */}
364	      <section className="mt-10">
365	        <h2 className="text-lg font-semibold text-gray-900 mb-4">Vendor Reviews</h2>
366	        <div className="space-y-3">
367	          {reviews.map((review) => {
368	            const statusInfo = REVIEW_STATUS_ICONS[review.review_status] || REVIEW_STATUS_ICONS.visible;
369	            return (
370	              <div key={review.id} className={`bg-white rounded-lg border border-gray-200 p-4 ${review.review_status === 'hidden' ? 'opacity-50' : ''}`}>
371	                <div className="flex items-start justify-between">
372	                  <div className="flex-1">
373	                    <div className="flex items-center space-x-2 mb-1">
374	                      <span className="text-sm font-semibold text-gray-800">{review.vendor_name}</span>
375	                      <div className="flex">
376	                        {Array.from({ length: 5 }, (_, i) => (
377	                          <span key={i} className={`text-sm ${i < review.rating ? 'text-yellow-400' : 'text-gray-300'}`}>&#9733;</span>
378	                        ))}
379	                      </div>
380	                      <span className={`text-xs font-medium ${statusInfo.color}`}>[{statusInfo.label}]</span>
381	                    </div>
382	                    {review.title && <h4 className="text-sm font-medium text-gray-700">{review.title}</h4>}
383	                    <p className="text-sm text-gray-600 mt-1">{review.body}</p>
384	                    {review.disclaimer_text && (
385	                      <p className="mt-2 text-xs text-orange-700 bg-orange-50 px-3 py-1.5 rounded italic">
386	                        {review.disclaimer_text}
387	                      </p>
388	                    )}
389	                  </div>
390	                </div>
391	              </div>
392	            );
393	          })}
394	          {reviews.length === 0 && (
395	            <div className="text-center py-8 text-gray-400">No reviews</div>
396	          )}
397	        </div>
398	      </section>
399	    </div>
400	  );
401	}
