1	import React, { useState, useEffect, useCallback } from 'react';
2	import client from '../api/client';
3	import LoadingSpinner from '../components/LoadingSpinner';
4	import { useAuthStore } from '../store/authStore';
5	
6	const STATUS_COLORS = {
7	  open: 'bg-gray-100 text-gray-700',
8	  matched: 'bg-green-100 text-green-700',
9	  variance_pending: 'bg-yellow-100 text-yellow-700',
10	  writeoff_suggested: 'bg-orange-100 text-orange-700',
11	  writeoff_approved: 'bg-blue-100 text-blue-700',
12	  settled: 'bg-green-200 text-green-800',
13	  disputed: 'bg-red-100 text-red-700',
14	  pending: 'bg-gray-100 text-gray-600',
15	  pending_approval: 'bg-yellow-100 text-yellow-700',
16	  manual_investigation: 'bg-red-100 text-red-700',
17	  paid: 'bg-green-200 text-green-800',
18	};
19	
20	const INVOICE_STATUS_COLORS = {
21	  pending: 'bg-gray-100 text-gray-600',
22	  matched: 'bg-green-100 text-green-700',
23	  variance_detected: 'bg-yellow-100 text-yellow-700',
24	  pending_approval: 'bg-orange-100 text-orange-700',
25	  manual_investigation: 'bg-red-100 text-red-700',
26	  approved: 'bg-blue-100 text-blue-700',
27	  rejected: 'bg-red-200 text-red-800',
28	  paid: 'bg-green-200 text-green-800',
29	};
30	
31	export default function Reconciliation() {
32	  const { hasAnyRole } = useAuthStore();
33	  // Only finance_analyst and system_admin can access cost allocation, ledger, compare, and exports
34	  const isFinanceOrAdmin = hasAnyRole('finance_analyst', 'system_admin');
35	
36	  const [activeTab, setActiveTab] = useState('invoices');
37	  const [invoices, setInvoices] = useState([]);
38	  const [settlements, setSettlements] = useState([]);
39	  const [costAllocation, setCostAllocation] = useState([]);
40	  const [orders, setOrders] = useState([]);
41	  const [loading, setLoading] = useState(true);
42	  const [error, setError] = useState(null);
43	  const [actionMsg, setActionMsg] = useState('');
44	
45	  // Statement comparison
46	  const [compareForm, setCompareForm] = useState({ vendor_id: '', statement_total: '', period_start: '', period_end: '' });
47	  const [compareResult, setCompareResult] = useState(null);
48	
49	  const fetchData = useCallback(async () => {
50	    setLoading(true);
51	    setError(null);
52	    try {
53	      const fetches = [
54	        client.get('/procurement/invoices'),
55	        client.get('/procurement/settlements'),
56	        client.get('/procurement/orders'),
57	      ];
58	      // Cost allocation is restricted to finance_analyst + system_admin
59	      if (isFinanceOrAdmin) {
60	        fetches.push(client.get('/procurement/cost-allocation'));
61	      }
62	      const results = await Promise.all(fetches);
63	      setInvoices(results[0].data || []);
64	      setSettlements(results[1].data || []);
65	      setOrders(results[2].data || []);
66	      setCostAllocation(isFinanceOrAdmin ? (results[3].data || []) : []);
67	    } catch (err) {
68	      setError(err.response?.data?.message || 'Failed to load reconciliation data');
69	    } finally {
70	      setLoading(false);
71	    }
72	  }, [isFinanceOrAdmin]);
73	
74	  useEffect(() => { fetchData(); }, [fetchData]);
75	
76	  const handleMatchInvoice = async (invoiceId, orderId) => {
77	    try {
78	      await client.post('/procurement/invoices/match', { invoice_id: invoiceId, order_id: orderId });
79	      setActionMsg('Invoice matched successfully');
80	      fetchData();
81	    } catch (err) {
82	      setError(err.response?.data?.message || 'Match failed');
83	    }
84	  };
85	
86	  const handleSettlementTransition = async (settlementId, action) => {
87	    try {
88	      await client.post('/procurement/settlements/transition', { settlement_id: settlementId, action });
89	      setActionMsg(`Settlement ${action} successful`);
90	      fetchData();
91	    } catch (err) {
92	      setError(err.response?.data?.message || 'Transition failed');
93	    }
94	  };
95	
96	  const handleCompare = async (e) => {
97	    e.preventDefault();
98	    setCompareResult(null);
99	    try {
100	      const res = await client.post('/procurement/reconciliation/compare', {
101	        vendor_id: parseInt(compareForm.vendor_id),
102	        statement_total: parseFloat(compareForm.statement_total),
103	        period_start: compareForm.period_start,
104	        period_end: compareForm.period_end,
105	      });
