200	// TestRealRequireRole_LearnerBlockedFromFinance tests that a learner gets 404
201	// from a finance-only endpoint using the real RequireRole middleware.
202	func TestRealRequireRole_LearnerBlockedFromFinance(t *testing.T) {
203		configSvc := services.NewConfigServiceForTest(map[string]models.Config{})
204		mw := &AuthMiddleware{configService: configSvc}
205	
206		e := echo.New()
207		financeGroup := e.Group("/api/procurement",
208			func(next echo.HandlerFunc) echo.HandlerFunc {
209				return func(c echo.Context) error {
210					tok := c.Request().Header.Get("Authorization")
211					if len(tok) < 8 {
212						return echo.NewHTTPError(http.StatusUnauthorized)
213					}
214					claims, err := jwt.ValidateToken(tok[7:])
215					if err != nil {
216						return echo.NewHTTPError(http.StatusUnauthorized)
217					}
218					c.Set("roles", claims.Roles)
219					c.Set("role_ids", claims.RoleIDs)
220					c.Set("user_id", claims.UserID)
221					c.Set("permissions", claims.Permissions)
222					return next(c)
223				}
224			},
225			mw.RequireRole("finance_analyst", "system_admin"),
226		)
227		financeGroup.GET("/settlements", func(c echo.Context) error {
228			return c.JSON(http.StatusOK, []interface{}{})
229		})
230		financeGroup.POST("/reconciliation/compare", func(c echo.Context) error {
231			return c.JSON(http.StatusOK, map[string]string{"ok": "true"})
232		})
233	
234		learnerToken := makeToken(t, 3, "test-session-id",
235			[]string{"learner"},
236			[]string{"learning.library.view"},
237		)
238		financeToken := makeToken(t, 6, "test-session-id",
239			[]string{"finance_analyst"},
240			[]string{"finance.reconciliation.view"},
241		)
242	
243		tests := []struct {
244			name       string
245			token      string
246			method     string
247			path       string
248			wantStatus int
249		}{
250			{"learner_blocked_settlements_GET", learnerToken, "GET", "/api/procurement/settlements", http.StatusNotFound},
251			{"learner_blocked_compare_POST", learnerToken, "POST", "/api/procurement/reconciliation/compare", http.StatusNotFound},
252			{"finance_allowed_settlements_GET", financeToken, "GET", "/api/procurement/settlements", http.StatusOK},
253			{"finance_allowed_compare_POST", financeToken, "POST", "/api/procurement/reconciliation/compare", http.StatusOK},
254		}
255	
256		for _, tc := range tests {
257			t.Run(tc.name, func(t *testing.T) {
258				req := httptest.NewRequest(tc.method, tc.path, nil)
259				req.Header.Set("Authorization", "Bearer "+tc.token)
260				rec := httptest.NewRecorder()
261				e.ServeHTTP(rec, req)
262				if rec.Code != tc.wantStatus {
263					t.Errorf("want %d, got %d", tc.wantStatus, rec.Code)
264				}
265			})
266		}
267	}
