27	// RequireAuth validates the JWT, checks session validity (idle/max), and injects claims into context.
28	func (m *AuthMiddleware) RequireAuth() echo.MiddlewareFunc {
29		return func(next echo.HandlerFunc) echo.HandlerFunc {
30			return func(c echo.Context) error {
31				authHeader := c.Request().Header.Get("Authorization")
32				if authHeader == "" {
33					return echo.NewHTTPError(http.StatusUnauthorized, "missing authorization header")
34				}
35	
36				parts := strings.SplitN(authHeader, " ", 2)
37				if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
38					return echo.NewHTTPError(http.StatusUnauthorized, "invalid authorization format")
39				}
40	
41				claims, err := jwt.ValidateToken(parts[1])
42				if err != nil {
43					return echo.NewHTTPError(http.StatusUnauthorized, "invalid or expired token")
44				}
45	
46				// Validate session (idle timeout / max lifetime)
47				session, err := m.authService.ValidateSession(c.Request().Context(), claims.SessionID)
48				if err != nil || session == nil {
49					return echo.NewHTTPError(http.StatusUnauthorized, "session expired")
50				}
51	
52				// Store claims in context for downstream handlers
53				c.Set("claims", claims)
54				c.Set("user_id", claims.UserID)
55				c.Set("username", claims.Username)
56				c.Set("roles", claims.Roles)
57				c.Set("role_ids", claims.RoleIDs)
58				c.Set("permissions", claims.Permissions)
59				c.Set("session_id", claims.SessionID)
60	
61				return next(c)
62			}
63		}
64	}
