66	// RequireRole checks that the authenticated user has at least one of the specified roles.
67	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
68	func (m *AuthMiddleware) RequireRole(roles ...string) echo.MiddlewareFunc {
69		return func(next echo.HandlerFunc) echo.HandlerFunc {
70			return func(c echo.Context) error {
71				userRoles, ok := c.Get("roles").([]string)
72				if !ok || len(userRoles) == 0 {
73					return echo.NewHTTPError(http.StatusNotFound)
74				}
75	
76				for _, required := range roles {
77					for _, userRole := range userRoles {
78						if required == userRole {
79							return next(c)
80						}
81					}
82				}
83	
84				// Feature invisibility: user without the role should not know the endpoint exists
85				return echo.NewHTTPError(http.StatusNotFound)
86			}
87		}
88	}
