113	// AppVersionCheck middleware checks the client's app version header and enforces compatibility.
114	// Clients below the minimum supported version enter a 14-day (configurable) read-only grace
115	// period. During grace, GET/HEAD/OPTIONS requests are allowed but writes are blocked.
116	// After the grace period expires, all requests are blocked.
117	// If no version header is provided, the client is treated as version "0.0.0" (oldest possible)
118	// so that the compatibility policy is still enforced.
119	func (m *AuthMiddleware) AppVersionCheck() echo.MiddlewareFunc {
120		return func(next echo.HandlerFunc) echo.HandlerFunc {
121			return func(c echo.Context) error {
122				clientVersion := c.Request().Header.Get("X-App-Version")
123	
124				minVersion, _ := m.configService.GetConfig("app.min_supported_version")
125				if minVersion == "" {
126					// No minimum version configured — skip enforcement
127					return next(c)
128				}
129	
130				if clientVersion == "" {
131					// Missing version header: treat as oldest client ("0.0.0")
132					// so the compatibility policy still applies.
133					clientVersion = "0.0.0"
134				}
135	
136				if compareVersions(clientVersion, minVersion) < 0 {
137					// Determine grace period: how long the min_version has been in effect
138					graceDays := 14
139					if val, ok := m.configService.GetConfig("app.read_only_grace_days"); ok {
140						var d int
141						if _, err := fmt.Sscanf(val, "%d", &d); err == nil && d > 0 {
142							graceDays = d
143						}
144					}
145	
146					// Get the timestamp when the min_supported_version was last updated
147					// (approximated by the config's updated_at). If not available, treat
148					// as if just updated (full grace period).
149					minVersionSetAt := m.configService.GetConfigUpdatedAt("app.min_supported_version")
150	
151					graceDeadline := minVersionSetAt.Add(time.Duration(graceDays) * 24 * time.Hour)
152					withinGrace := time.Now().Before(graceDeadline)
153	
154					c.Response().Header().Set("X-App-Deprecated", "true")
155					c.Response().Header().Set("X-Min-Version", minVersion)
156	
157					if !withinGrace {
158						// Grace period expired: hard block ALL requests
159						return echo.NewHTTPError(http.StatusUpgradeRequired,
160							"client version unsupported and grace period expired; upgrade to "+minVersion+" or later")
161					}
162	
163					// Within grace period: allow read-only access
164					c.Set("read_only", true)
165					daysLeft := int(time.Until(graceDeadline).Hours() / 24)
166					c.Response().Header().Set("X-Grace-Days-Remaining", fmt.Sprintf("%d", daysLeft))
167	
168					method := c.Request().Method
169					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
170						return echo.NewHTTPError(http.StatusUpgradeRequired,
171							fmt.Sprintf("client version unsupported; read-only access for %d more days. Upgrade to %s or later.",
172								daysLeft, minVersion))
173					}
174				}
175	
176				return next(c)
177			}
178		}
179	}
