181	// compareVersions compares semver strings. Returns -1, 0, or 1.
182	func compareVersions(a, b string) int {
183		partsA := strings.Split(a, ".")
184		partsB := strings.Split(b, ".")
185	
186		maxLen := len(partsA)
187		if len(partsB) > maxLen {
188			maxLen = len(partsB)
189		}
190	
191		for i := 0; i < maxLen; i++ {
192			var va, vb int
193			if i < len(partsA) {
194				for _, ch := range partsA[i] {
195					if ch >= '0' && ch <= '9' {
196						va = va*10 + int(ch-'0')
197					}
198				}
199			}
200			if i < len(partsB) {
201				for _, ch := range partsB[i] {
202					if ch >= '0' && ch <= '9' {
203						vb = vb*10 + int(ch-'0')
204					}
205				}
206			}
207			if va < vb {
208				return -1
209			}
210			if va > vb {
211				return 1
212			}
213		}
214		return 0
215	}
