386	func TestRealVersionGate_AndRBAC_Combined(t *testing.T) {
387		// Grace period active (min set 5 days ago)
388		configs := map[string]models.Config{
389			"app.min_supported_version": {
390				Key:       "app.min_supported_version",
391				Value:     "2.0.0",
392				UpdatedAt: time.Now().Add(-5 * 24 * time.Hour),
393			},
394		}
395		configSvc := services.NewConfigServiceForTest(configs)
396		mw := &AuthMiddleware{configService: configSvc}
397	
398		e := echo.New()
399		e.Use(mw.AppVersionCheck())
400	
401		finGroup := e.Group("/api/procurement",
402			func(next echo.HandlerFunc) echo.HandlerFunc {
403				return func(c echo.Context) error {
404					tok := c.Request().Header.Get("Authorization")
405					if len(tok) < 8 {
406						return echo.NewHTTPError(http.StatusUnauthorized)
407					}
408					claims, err := jwt.ValidateToken(tok[7:])
409					if err != nil {
410						return echo.NewHTTPError(http.StatusUnauthorized)
411					}
412					c.Set("roles", claims.Roles)
413					return next(c)
414				}
415			},
416			mw.RequireRole("finance_analyst", "system_admin"),
417		)
418		finGroup.GET("/settlements", func(c echo.Context) error {
419			return c.JSON(http.StatusOK, []interface{}{})
420		})
421	
422		learnerToken := makeToken(t, 3, "test-session-id", []string{"learner"}, []string{})
423	
424		t.Run("learner_old_version_blocked_by_RBAC_first", func(t *testing.T) {
425			// Even with old version (within grace), RBAC blocks learner -> 404
426			req := httptest.NewRequest(http.MethodGet, "/api/procurement/settlements", nil)
427			req.Header.Set("Authorization", "Bearer "+learnerToken)
428			req.Header.Set("X-App-Version", "1.0.0")
429			rec := httptest.NewRecorder()
430			e.ServeHTTP(rec, req)
