type inMemorySessionValidator struct {
	sessions map[string]*models.Session
}

func (v *inMemorySessionValidator) ValidateSession(_ context.Context, sessionID string) (*models.Session, error) {
	sess, ok := v.sessions[sessionID]
	if !ok {
		return nil, fmt.Errorf("session not found")
	}
	return sess, nil
}

func newTestSession(sessionID string) *models.Session {
	return &models.Session{
		ID:           sessionID,
