		ExpiresAt:    time.Now().Add(24 * time.Hour),
	}
}

// TestFullRequireAuth_DisputeTransition_RoleGate verifies the full RequireAuth +
// RequireRole chain for the dispute transition endpoint using no auth shims.
// After H-01A fix: procurement_specialist, content_moderator, system_admin are allowed;
// learner, finance_analyst, approver are blocked.
func TestFullRequireAuth_DisputeTransition_RoleGate(t *testing.T) {
	const sid = "session-dispute-test"
	sessionStore := &inMemorySessionValidator{
		sessions: map[string]*models.Session{sid: newTestSession(sid)},
	}
	configSvc := services.NewConfigServiceForTest(map[string]models.Config{})
	mw := &AuthMiddleware{authService: sessionStore, configService: configSvc}

	e := echo.New()
	g := e.Group("/api/procurement",
		mw.RequireAuth(),
		mw.RequireRole("procurement_specialist", "content_moderator", "system_admin"),
	)
	g.POST("/disputes/transition", func(c echo.Context) error {
		return c.JSON(http.StatusOK, map[string]string{"ok": "true"})
	})

	roleExpectations := []struct {
		role    string
		allowed bool
	}{
		{"system_admin", true},
		{"content_moderator", true},
		{"procurement_specialist", true},
		{"approver", false},
		{"finance_analyst", false},
		{"learner", false},
	}

	for _, tc := range roleExpectations {
		t.Run("full_chain_dispute_transition_"+tc.role, func(t *testing.T) {
			tok := makeToken(t, 1, sid, []string{tc.role}, []string{})
			req := httptest.NewRequest(http.MethodPost, "/api/procurement/disputes/transition", nil)
			req.Header.Set("Authorization", "Bearer "+tok)
			rec := httptest.NewRecorder()
			e.ServeHTTP(rec, req)

			if tc.allowed && rec.Code != http.StatusOK {
				t.Errorf("role %s should be allowed (200), got %d", tc.role, rec.Code)
			}
			if !tc.allowed && rec.Code != http.StatusNotFound {
				t.Errorf("role %s should be blocked (404), got %d", tc.role, rec.Code)
			}
		})
	}
}

