func TestFullRequireAuth_SessionExpired_Returns401(t *testing.T) {
	// Empty session store — no valid sessions
	sessionStore := &inMemorySessionValidator{sessions: map[string]*models.Session{}}
	configSvc := services.NewConfigServiceForTest(map[string]models.Config{})
	mw := &AuthMiddleware{authService: sessionStore, configService: configSvc}

	e := echo.New()
	g := e.Group("/api/procurement", mw.RequireAuth(), mw.RequireRole("system_admin"))
	g.GET("/disputes", func(c echo.Context) error {
