2	import client from '../api/client';
3	
4	const STORAGE_KEY = 'wlpr_auth';
5	
6	function loadPersistedAuth() {
7	  try {
8	    const raw = localStorage.getItem(STORAGE_KEY);
9	    if (!raw) return null;
10	    const data = JSON.parse(raw);
11	    // Check if token is still present (basic check; server validates fully)
12	    if (data.token) return data;
13	    return null;
14	  } catch {
15	    return null;
16	  }
17	}
18	
19	function persistAuth(state) {
20	  if (state.token) {
21	    localStorage.setItem(
22	      STORAGE_KEY,
23	      JSON.stringify({
24	        token: state.token,
25	        user: state.user,
26	      })
27	    );
28	  } else {
29	    localStorage.removeItem(STORAGE_KEY);
30	  }
31	}
32	
33	const persisted = loadPersistedAuth();
34	
35	export const useAuthStore = create((set, get) => ({
36	  // Auth state
37	  token: persisted?.token || null,
38	  user: persisted?.user || null,
39	  isAuthenticated: !!persisted?.token,
40	  mfaPending: false,
41	  mfaSessionId: null,
42	
43	  // UI state
44	  loading: false,
45	  error: null,
46	  accessDenied: false,
47	  versionBlocked: false,
48	  deprecationWarning: null,
49	
50	  // Login step 1: credentials
51	  login: async (username, password) => {
52	    set({ loading: true, error: null, accessDenied: false });
53	    try {
54	      const res = await client.post('/auth/login', { username, password });
55	      const data = res.data;
56	
57	      if (data.requires_mfa) {
58	        set({
59	          loading: false,
60	          mfaPending: true,
61	          mfaSessionId: data.session_id,
62	        });
63	        return { requiresMFA: true };
64	      }
65	
66	      const newState = {
67	        token: data.token,
68	        user: data.user,
69	        isAuthenticated: true,
70	        loading: false,
71	        mfaPending: false,
72	        mfaSessionId: null,
73	      };
74	      set(newState);
75	      persistAuth(newState);
76	      return { requiresMFA: false };
77	    } catch (err) {
78	      const msg =
79	        err.response?.data?.message || err.message || 'Login failed';
80	      set({ loading: false, error: msg });
81	      throw new Error(msg);
82	    }
83	  },
84	
85	  // Login step 2: MFA verification
86	  verifyMFA: async (code) => {
87	    const { mfaSessionId } = get();
88	    if (!mfaSessionId) {
89	      set({ error: 'No MFA session active' });
90	      throw new Error('No MFA session active');
91	    }
92	
93	    set({ loading: true, error: null });
94	    try {
95	      const res = await client.post('/auth/mfa/verify', {
96	        code,
97	        session_id: mfaSessionId,
98	      });
99	      const data = res.data;
100	
101	      const newState = {
102	        token: data.token,
103	        user: data.user,
104	        isAuthenticated: true,
105	        loading: false,
106	        mfaPending: false,
107	        mfaSessionId: null,
108	      };
109	      set(newState);
110	      persistAuth(newState);
111	    } catch (err) {
112	      const msg =
113	        err.response?.data?.message || err.message || 'MFA verification failed';
114	      set({ loading: false, error: msg });
115	      throw new Error(msg);
116	    }
117	  },
118	
119	  // Logout: clear all state
120	  logout: async () => {
121	    const { token } = get();
122	    if (token) {
123	      try {
124	        await client.post('/auth/logout');
125	      } catch {
126	        // Ignore logout API errors
127	      }
128	    }
129	    set({
130	      token: null,
131	      user: null,
132	      isAuthenticated: false,
133	      mfaPending: false,
134	      mfaSessionId: null,
135	      loading: false,
136	      error: null,
137	      accessDenied: false,
138	      versionBlocked: false,
139	      deprecationWarning: null,
140	    });
141	    localStorage.removeItem(STORAGE_KEY);
142	  },
143	
144	  // Fetch current user info
145	  fetchMe: async () => {
146	    try {
147	      const res = await client.get('/auth/me');
148	      set({ user: { ...get().user, ...res.data } });
149	    } catch {
150	      // Token might be invalid
151	      get().logout();
152	    }
153	  },
154	
155	  // MFA setup
156	  setupMFA: async () => {
157	    const res = await client.post('/auth/mfa/setup');
158	    return res.data; // { secret, qr_code }
159	  },
160	
161	  confirmMFA: async (code) => {
162	    const res = await client.post('/auth/mfa/confirm', { code });
163	    return res.data; // { message, recovery_codes }
164	  },
165	
166	  disableMFA: async () => {
167	    await client.post('/auth/mfa/disable');
168	    set((state) => ({
169	      user: state.user ? { ...state.user, mfa_enabled: false } : null,
170	    }));
171	  },
172	
173	  // UI state setters
174	  clearError: () => set({ error: null }),
175	  setAccessDenied: (val) => set({ accessDenied: val }),
176	  setVersionBlocked: (val) => set({ versionBlocked: val }),
177	  setDeprecationWarning: (minVersion) =>
178	    set({ deprecationWarning: minVersion }),
179	
180	  // Permission helpers
181	  hasRole: (role) => {
182	    const { user } = get();
183	    return user?.roles?.some((r) => r.name === role) || false;
184	  },
185	
186	  hasPermission: (perm) => {
187	    const { user } = get();
188	    return user?.permissions?.includes(perm) || false;
189	  },
190	
191	  hasAnyRole: (...roles) => {
192	    const { user } = get();
193	    return user?.roles?.some((r) => roles.includes(r.name)) || false;
194	  },
195	}));
196
